var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"결국 혼자만 남았구나.","JPN":"結局一人になってしまったな。","ENG":"You are the only one left.","TWN":"最終只剩下你一個人了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그런 힘을 가지고도, 아무것도 지켜내지 못한 감상은 어떻지?","JPN":"そのような力を持っているにも関わらず、何一つ守れなかった心境はどうだ？","ENG":"What does it feel like to not be able to protect anything even with that power of yours?","TWN":"擁有那樣的力量，卻什麼都保護不了，感覺如何？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"용서 못해…","JPN":"許さない……","ENG":"Unforgivable...","TWN":"無法原諒…"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"아무 죄 없는 사람들을… 그렇게 죽이다니…","JPN":"罪のない人たちを……こんなふうに殺すなんて……","ENG":"How could you... kill all those innocent people...?","TWN":"無辜的人們…竟然就這麼被你殺害…"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"죄가 없다고?","JPN":"罪がない？","ENG":"Innocent, you say?","TWN":"說自己，無辜嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"어리석구나. 너희가 가진 그 덧없는 육신이 바로 죄악의 온상인 것을.","JPN":"愚かな。貴様らが持つその儚い肉体こそ、罪の温床である。","ENG":"How foolish. That fleeting body of yours is the hotbed of sin.","TWN":"真是愚蠢，你們那脆弱的肉體本身就是罪惡的溫床。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"웃기지… 마…","JPN":"ふざけ……ないで……","ENG":"Don't... make me laugh...","TWN":"別…開玩笑…"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"내 친히 그 육신을 단죄해줄 테니.","JPN":"余がこの手でその肉体を断罪してやろう。","ENG":"I shall condemn that body myself.","TWN":"我會親自審判你的肉體。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"받아들여라.","JPN":"受け入れろ。","ENG":"Accept your end.","TWN":"接受吧。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_ENERGY_ATTACK_BIG_20"},{"id":"L14_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"더는… 몸이 안 움직여.","JPN":"もう……体が動かない。","ENG":"I can't... move anymore.","TWN":"再也…動不了了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"다들… 부디 무사하길…","JPN":"みんな……どうか無事でいて……","ENG":"I hope... everyone is safe...","TWN":"大家…一定要平安…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_CONFUSION"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"당신은…?","JPN":"あなたは……？","ENG":"You are…?","TWN":"你是…？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORS_ROOT_ARMOR_NULL","text":{"KOREA":"여긴 네가 쓰러질 곳이 아니다.","JPN":"ここはそなたが倒れるような場所ではない。","ENG":"This is not where you fall.","TWN":"你倒下的地方不是這裡。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"이 목소리는… 역시…","JPN":"この声は……やっぱり……","ENG":"That voice... I knew it...","TWN":"這個聲音是…果然是…"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"에클레시아 추기경님인가요?","JPN":"エクレシア枢機卿ですか？","ENG":"Are you Cardinal Ecclesia?","TWN":"艾克蕾西亞主教…？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORS_ROOT_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORS_ROOT_ARMOR_NULL","text":{"KOREA":"곧 마왕이 남은 인류의 터전을 침공할 것이다.","JPN":"じきに魔王が生き残った人類の住処を侵攻するだろう。","ENG":"Soon, the Demon Lord will attack the remaining settlements of humanity.","TWN":"魔王即將侵襲人類最後的家園。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORS_ROOT_ARMOR_NULL","text":{"KOREA":"마왕의 목적은 인류의 종말로 하여금 가능성의 영역으로 뻗어나가는 것.","JPN":"魔王の目的は人類の終末。そして可能性の領域へと進むこと。","ENG":"Her goal is to expand into the realm of possibilities by bringing about the end of humanity.","TWN":"她的目的是透過人類的終結，擴展到可能性的領域。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORS_ROOT_ARMOR_NULL","text":{"KOREA":"너는 돌아가서 살아남은 이들을 종말로부터 지켜라.","JPN":"そなたは戻り、生き残った人類を終末から守れ。","ENG":"You must go back and save the survivors from the apocalypse.","TWN":"你必須回去，保護倖存者免于終結。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"저도 당신과 함께 싸우겠어요! 같은 순례단의 일원으로서…!","JPN":"私もあなたと一緒に戦います！　同じ巡礼団の一員として……！","ENG":"I'll fight with you! As a member of the pilgrimage...!","TWN":"我也要和你一起戰鬥！作為同一個朝聖團的成員…！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORS_ROOT_ARMOR_NULL","text":{"KOREA":"…순례단은 이제 없다.","JPN":"……巡礼団はもう存在しない。","ENG":"...The pilgrimage is no more.","TWN":"…朝聖團已經不存在了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORS_ROOT_ARMOR_NULL","text":{"KOREA":"그릇된 신념과 함께 몰락하여, 갑옷에 유폐된 죄인만이 있을 뿐.","JPN":"間違った信念と共に没落し、鎧に幽閉された罪人が残っているだけ。","ENG":"All that is left is a sinner who has fallen with false faith, imprisoned in armor.","TWN":"只剩下一個與錯誤的信念一起墮落，被囚禁在鎧甲中的罪人。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"마왕의 짓인가요…?","JPN":"魔王の仕業ですか……？","ENG":"Is it the doing of the Demon Lord...?","TWN":"是魔王幹的嗎…？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"당신과 엘리시온을 그렇게 만든 건…! 마왕인 거죠?!","JPN":"あなたとエリシオンをそうさせたのは……！　魔王なんですよね！？","ENG":"What happened to you and Elysion...! Is it the Demon Lord's doing?!","TWN":"把你和艾利森變成這樣的…！是魔王對吧？！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORS_ROOT_ARMOR_NULL","text":{"KOREA":"…그래.","JPN":"……そうだ。","ENG":"...Yes.","TWN":"…是。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORS_ROOT_ARMOR_NULL","text":{"KOREA":"그리고 그 마왕을 만들어낸 것 또한… 나다.","JPN":"そして、その魔王を作り出したのもまた……我だ。","ENG":"And I... am also the one who created the Demon Lord.","TWN":"但促成那個魔王的…也是我。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"네…?","JPN":"はい……？","ENG":"What...?","TWN":"什麼…？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그게 무슨 소리죠? 제가 아는 추기경님은 지금껏 마왕을 토벌하기 위해…!","JPN":"それ、どういうことですか？　私の知ってる枢機卿は今まで魔王を討伐するために……！","ENG":"What do you mean? The Cardinal I know has been trying to defeat the Demon Lord–!","TWN":"這是什麼意思？據我所知主教一直在討伐魔王…！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORS_ROOT_ARMOR_NULL","text":{"KOREA":"종말에 진정한 원흉은 없다. 그저 모두가 그렇게 희생되었을 뿐.","JPN":"終末に真なる元凶などない。ただ、みんなの犠牲があるだけだ。","ENG":"There is no true cause of the apocalypse. Everyone has merely been sacrificed.","TWN":"那場終結裡沒有真正的元兇。所有人都因此而犧牲了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MORS_ROOT_ARMOR_NULL","text":{"KOREA":"그러니 돌아가라.","JPN":"だから、戻れ。","ENG":"So, go back.","TWN":"所以回去吧。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MORS_ROOT_ARMOR_NULL","text":{"KOREA":"…모드레드.","JPN":"……モードレッド。","ENG":"...Mordred.","TWN":"…莫德雷德。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L47_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"내 몸에… 빛이…?","JPN":"私の体が……光って……？","ENG":"My body... is shining...?","TWN":"我的身體…在發光…？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MORS_ROOT_ARMOR_NULL","text":{"KOREA":"시간이 얼마 남지 않았으니.","JPN":"時が迫っている。","ENG":"There is not much time left.","TWN":"時間不多了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MORS_ROOT_ARMOR_NULL","text":{"KOREA":"뜻이 같은 이들과… 종말에 대비해라.","JPN":"同じ意志を持つ者たちと……終末に備えろ。","ENG":"Prepare for the end... with the others who share your will.","TWN":"與志同道合的人…準備迎接終結。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"에클레시아…?","JPN":"エクレシア……？","ENG":"Her Eminence...?","TWN":"艾克蕾西亞…？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"잠시만요…! 저는 아직 할 말이…!","JPN":"待ってください……！　私はまだ言いたいことが……！","ENG":"Wait...! I still have more to say–!","TWN":"等一下…！我還有話要說…！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MORS_ROOT_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_ROOT_ARMOR_NULL","text":{"KOREA":"약속을 지키지 못해… 미안하구나.","JPN":"約束を守れず……すまないな。","ENG":"I am sorry... for not keeping my promise.","TWN":"沒能遵守約定…對不起。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"처벌을 피해 도망친 죄인이 제 발로 다시 돌아오다니…","JPN":"処罰から逃げた罪人が自らの足で戻ってくるとは……","ENG":"A runaway sinner returning on her own will...","TWN":"逃避懲罰的罪人竟然自己回來了…"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"곧 죽을 인간 한 명을 구하기 위해 널 희생하겠다는 거냐?","JPN":"どうせすぐに死ぬ運命の人間一人を救うため、自分を犠牲にするつもりか？","ENG":"Are you going to sacrifice yourself just to save one human who will soon die?","TWN":"你是要為了救一個快死的人而犧牲自己嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_ROOT_ARMOR_NULL","text":{"KOREA":"말이 길구나, 솔리키타티오.","JPN":"無駄話が多いな、ソリキタティオ。","ENG":"Too much talk from you, Sollicitatio.","TWN":"廢話太多了，索爾奇塔提奧。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_ROOT_ARMOR_NULL","text":{"KOREA":"너와 나 사이를 정의할 수 있는 건… 이 차가운 날붙이뿐이다.","JPN":"貴様と我の間を定義できるのは……この冷たい刃物だけ。","ENG":"The only thing that will define our discord... is this cold blade.","TWN":"能定義你我關係的…只有這冰冷的刀刃。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"갑옷에 갇힌 주제에 입만 살았군.","JPN":"鎧に閉じ込めれらている分際で、ほざくでない。","ENG":"All talk from someone trapped in armor.","TWN":"雖然困在鎧甲中，嘴上功夫還是很厲害。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"벌써 망각했나? 너 같은 위선자는 아무것도 지킬 수 없다는 걸.","JPN":"もう忘れたか？　貴様のような偽善者は何も守れないということを。","ENG":"Or have you already forgotten? A hypocrite like you cannot protect anything.","TWN":"已經忘了嗎？像你這樣的偽善者什麼都守護不了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MORS_ROOT_ARMOR_NULL","text":{"KOREA":"내가 실패한 죄인일지 언정…","JPN":"我は失敗した罪人ではあるが……","ENG":"Though I may be a failed sinner...","TWN":"就算我是無藥可救的罪人…"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MORS_ROOT_ARMOR_NULL","text":{"KOREA":"그저 묶인 채 방관하는 것을 속죄로 삼진 않으리라.","JPN":"ただ縛られ傍観することを償いだとは思わない。","ENG":"I will not atone for my sins by neglecting.","TWN":"也不會把束手旁觀當作贖罪。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_ROOT_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};